237→async fn shutdown_signal() {
238→    let ctrl_c = tokio::signal::ctrl_c();
239→
240→    #[cfg(unix)]
241→    {
242→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
243→            .expect("failed to install SIGTERM handler");
244→        tokio::select! {
245→            _ = ctrl_c => {},
246→            _ = sigterm.recv() => {},
247→        }
248→    }
249→
250→    #[cfg(not(unix))]
251→    {
252→        ctrl_c.await.ok();
253→    }
254→
255→    tracing::info!("Received shutdown signal, draining connections...");
256→}
