267→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
268→    let path = data_dir.join("last_session");
269→    let raw = std::fs::read_to_string(path).ok()?;
270→    let session = raw.trim();
271→    if session.is_empty() {
272→        None
273→    } else {
274→        Some(session.to_owned())
275→    }
276→}
