278→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
279→    std::fs::create_dir_all(data_dir)?;
280→    std::fs::write(data_dir.join("last_session"), session)?;
281→    Ok(())
282→}
