284→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
285→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
286→async fn resolve_session(
287→    data_dir: &Path,
288→    requested: Option<String>,
289→    base_url: Option<&str>,
290→) -> String {
291→    if let Some(session) = requested {
292→        return session;
293→    }
294→
295→    if let Some(session) = read_last_session_hint(data_dir) {
296→        return session;
297→    }
298→
299→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
300→    if let Some(url) = base_url {
301→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
302→            return session;
303→        }
304→    }
305→
306→    "default".to_owned()
307→}
