321→/// Build provider from resolved configuration.
322→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
323→    let pc = resolved.provider_config.as_ref();
324→
325→    match resolved.provider.as_str() {
326→        "mock" => {
327→            tracing::warn!("Provider: MockProvider (forced via config)");
328→            Ok(Arc::new(MockProvider))
329→        }
330→        "openai" | "codex" | "openai-codex" => {
331→            // Try OAuth credential first, then fall back to env var / resolved config.
332→            if let Some(p) = try_openai_oauth_provider() {
333→                return Ok(p);
334→            }
335→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
336→                resolved.model.as_deref(),
337→                pc.and_then(|p| p.base_url.as_deref()),
338→                pc.and_then(|p| p.max_tokens),
339→            )?;
340→            tracing::info!(model = %config.model, "Provider: OpenAI");
341→            Ok(Arc::new(
342→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
343→            ))
344→        }
345→        "ollama" => {
346→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
347→                resolved.model.as_deref(),
348→                pc.and_then(|p| p.base_url.as_deref()),
349→                pc.and_then(|p| p.max_tokens),
350→                pc.and_then(|p| p.enable_streaming),
351→            )?;
352→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
353→            Ok(Arc::new(
354→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
355→            ))
356→        }
357→        "anthropic" => {
358→            let config = AnthropicConfig::from_resolved(
359→                resolved.model.as_deref(),
360→                pc.and_then(|p| p.base_url.as_deref()),
361→                pc.and_then(|p| p.max_tokens),
362→            )?;
363→            tracing::info!(model = %config.model, "Provider: Anthropic");
364→            Ok(Arc::new(AnthropicProvider::new(config)))
365→        }
366→        // Auto-detect: try providers in order
367→        _ => {
368→            if let Ok(config) = AnthropicConfig::from_env() {
369→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
370→                Ok(Arc::new(AnthropicProvider::new(config)))
371→            } else if let Some(p) = try_openai_oauth_provider() {
372→                Ok(p)
373→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
374→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
375→                Ok(Arc::new(
376→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
377→                ))
378→            } else {
379→                tracing::warn!(
380→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
381→                );
382→                Ok(Arc::new(MockProvider))
383→            }
384→        }
385→    }
386→}
