388→fn run_serve(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
389→    let workspace_root = std::env::current_dir()?;
390→
391→    // --- Lago persistence ---
392→    let journal_path = data_dir.join("journal.redb");
393→    let blobs_path = data_dir.join("blobs");
394→    std::fs::create_dir_all(&blobs_path)?;
395→
396→    tracing::info!(
397→        workspace = %workspace_root.display(),
398→        journal = %journal_path.display(),
399→        blobs = %blobs_path.display(),
400→        provider = %resolved.provider,
401→        model = ?resolved.model,
402→        port = resolved.port,
403→        "Starting arcan"
404→    );
405→
406→    let journal = RedbJournal::open(&journal_path)?;
407→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
408→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
409→
410→    // --- Policies ---
411→    let fs_policy = FsPolicy::new(workspace_root.clone());
412→    let sandbox_policy = SandboxPolicy {
413→        workspace_root: workspace_root.clone(),
414→        shell_enabled: true,
415→        network: NetworkPolicy::AllowAll,
416→        allowed_env: BTreeSet::new(),
417→        max_execution_ms: 10_000,
418→        max_stdout_bytes: 1024 * 1024,
419→        max_stderr_bytes: 1024 * 1024,
420→        max_processes: 10,
421→        max_memory_mb: 512,
422→    };
423→
424→    // --- Tools ---
425→    let mut registry = ToolRegistry::default();
426→    registry.register(ReadFileTool::new(fs_policy.clone()));
427→    registry.register(WriteFileTool::new(fs_policy.clone()));
428→    registry.register(ListDirTool::new(fs_policy.clone()));
429→    registry.register(EditFileTool::new(fs_policy.clone()));
430→    registry.register(GlobTool::new(fs_policy.clone()));
431→    registry.register(GrepTool::new(fs_policy));
432→
433→    let runner = Box::new(LocalCommandRunner);
434→    registry.register(BashTool::new(sandbox_policy, runner));
435→
436→    let memory_dir = data_dir.join("memory");
437→    std::fs::create_dir_all(&memory_dir)?;
438→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
439→    registry.register(WriteMemoryTool::new(memory_dir));
440→
441→    // --- Governed memory tools (event-sourced via Lago) ---
442→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
443→    registry.register(MemoryQueryTool::new(memory_projection));
444→    registry.register(MemoryProposeTool::new(journal.clone()));
445→    registry.register(MemoryCommitTool::new(journal.clone()));
446→
447→    // --- Provider ---
448→    let provider = build_provider(resolved)?;
449→
450→    // --- Canonical aiOS runtime adapters ---
451→    let event_store: Arc<dyn EventStorePort> =
452→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
453→    // Shared handle: starts empty, filled after runtime creation.
454→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
455→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::new(
456→        provider,
457→        registry.definitions(),
458→        streaming_sender.clone(),
459→    ));
460→    let observer = Arc::new(LakeFsObserver {
461→        workspace_root: workspace_root.clone(),
462→        journal: journal.clone(),
463→        blob_store: _blob_store,
464→    });
465→    let tool_harness: Arc<dyn ToolHarnessPort> =
466→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
467→    let policy_gate: Arc<dyn PolicyGatePort> =
468→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
469→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
470→
471→    let runtime = Arc::new(KernelRuntime::new(
472→        RuntimeConfig::new(data_dir.to_path_buf()),
473→        event_store,
474→        provider_adapter,
475→        tool_harness,
476→        approvals,
477→        policy_gate,
478→    ));
479→
480→    // Wire the broadcast sender now that the runtime exists.
481→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
482→
483→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
484→    let data_dir_owned = data_dir.to_path_buf();
485→    let port = resolved.port;
486→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
487→        .enable_all()
488→        .build()?;
489→
490→    tokio_runtime.block_on(async move {
491→        // --- HTTP Server ---
492→        let router = create_canonical_router(runtime);
493→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
494→        let listener = TcpListener::bind(addr).await?;
495→
496→        tracing::info!(%addr, "Listening");
497→        axum::serve(listener, router)
498→            .with_graceful_shutdown(shutdown_signal())
499→            .await?;
500→
501→        // Clean up PID file on graceful shutdown.
502→        daemon::remove_pid_file(&data_dir_owned);
503→
504→        tracing::info!("Server shut down gracefully");
505→        Ok(())
506→    })
507→}
