693→    }
694→    let local_path = config::local_config_path(data_dir);
695→    let exists = local_path.exists();
696→    println!(
697→        "Local cfg:  {} {}",
698→        local_path.display(),
699→        if exists { "" } else { "(not found)" }
700→    );
701→
702→    Ok(())
703→}
