705→#[allow(clippy::print_stderr)]
706→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
707→    // Normalize to canonical provider name for config persistence.
708→    let canonical = match provider {
709→        "codex" | "openai-codex" => "openai",
710→        other => other,
711→    };
712→
713→    match provider {
714→        "openai" | "codex" | "openai-codex" => {
715→            if device {
716→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
717→            } else {
718→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
719→            }
720→        }
721→        _ => {
722→            return Err(anyhow::anyhow!(
723→                "Unknown provider '{provider}'. Supported: openai"
724→            ));
725→        }
726→    }
727→
728→    // Set the provider as the new default after successful login.
729→    let mut file_config = config::load_config(data_dir);
730→    file_config.set_key("provider", canonical).ok();
731→    config::save_config(data_dir, &file_config)?;
732→    eprintln!("Default provider set to '{canonical}'");
733→
734→    Ok(())
735→}
736→
737→#[allow(clippy::print_stderr)]
738→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
739→    // Normalize provider name for credential lookup.
740→    let normalized = match provider {
741→        "codex" | "openai-codex" => "openai",
742→        other => other,
743→    };
744→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
745→
746→    // Clear the default provider if it matches the one being logged out.
747→    let mut file_config = config::load_config(data_dir);
748→    if file_config.defaults.provider.as_deref() == Some(normalized) {
749→        file_config.defaults.provider = None;
750→        config::save_config(data_dir, &file_config)?;
751→        eprintln!("Default provider cleared");
752→    }
753→
754→    eprintln!("Logged out of {provider}");
755→    Ok(())
756→}
