758→fn main() -> anyhow::Result<()> {
759→    let cli = Cli::parse();
760→    let data_dir = resolve_data_dir(&cli.data_dir)?;
761→
762→    // Load layered config.
763→    let file_config = config::load_config(&data_dir);
764→
765→    match cli.command {
766→        Some(Command::Serve {
767→            max_iterations,
768→            approval_timeout,
769→        }) => {
770→            // Structured logging to stderr for daemon mode
771→            tracing_subscriber::fmt()
772→                .with_env_filter(EnvFilter::from_default_env())
773→                .init();
774→
775→            let resolved = config::resolve(
776→                &file_config,
777→                cli.provider.as_deref(),
778→                cli.model.as_deref(),
779→                cli.port,
780→                max_iterations,
781→                approval_timeout,
782→            );
783→
784→            run_serve(&data_dir, &resolved)
785→        }
786→        Some(Command::Chat { session, url }) => {
787→            // File-based logging for TUI mode (don't clobber the terminal)
788→            let log_dir = data_dir.join("logs");
789→            std::fs::create_dir_all(&log_dir)?;
790→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
791→            tracing_subscriber::fmt()
792→                .with_writer(file_appender)
793→                .with_env_filter(EnvFilter::from_default_env())
794→                .init();
795→
796→            let resolved = config::resolve(
797→                &file_config,
798→                cli.provider.as_deref(),
799→                cli.model.as_deref(),
800→                cli.port,
801→                None,
802→                None,
803→            );
804→
805→            let runtime = tokio::runtime::Builder::new_multi_thread()
806→                .enable_all()
807→                .build()?;
808→            runtime.block_on(run_chat(data_dir, &resolved, session, url))
809→        }
810→        Some(Command::Login { provider, device }) => run_login(&provider, device, &data_dir),
811→        Some(Command::Logout { provider }) => run_logout(&provider, &data_dir),
812→        Some(Command::Run {
