814→            session,
815→            url,
816→            json,
817→        }) => {
818→            // File-based logging for CLI mode (don't clobber stdout)
819→            let log_dir = data_dir.join("logs");
820→            std::fs::create_dir_all(&log_dir)?;
821→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
822→            tracing_subscriber::fmt()
823→                .with_writer(file_appender)
824→                .with_env_filter(EnvFilter::from_default_env())
825→                .init();
826→
827→            let resolved = config::resolve(
828→                &file_config,
829→                cli.provider.as_deref(),
830→                cli.model.as_deref(),
831→                cli.port,
832→                None,
833→                None,
834→            );
835→
836→            let runtime = tokio::runtime::Builder::new_multi_thread()
837→                .enable_all()
838→                .build()?;
839→            runtime.block_on(run_message(
840→                data_dir, &resolved, message, session, url, json,
841→            ))
842→        }
843→        Some(Command::Config { action }) => run_config(&data_dir, action),
844→        Some(Command::Status) => {
845→            let resolved = config::resolve(
846→                &file_config,
