873→        }
874→        None => {
875→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
876→            let log_dir = data_dir.join("logs");
877→            std::fs::create_dir_all(&log_dir)?;
878→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
