187→/// Global config path: `~/.config/arcan/config.toml`
188→pub fn global_config_path() -> Option<PathBuf> {
189→    dirs::config_dir().map(|d| d.join("arcan").join("config.toml"))
190→}
191→
192→/// Project-local config path: `<data_dir>/config.toml`
193→pub fn local_config_path(data_dir: &Path) -> PathBuf {
194→    data_dir.join("config.toml")
195→}
196→
197→/// Load and merge config from global + local files.
198→pub fn load_config(data_dir: &Path) -> ArcanConfig {
199→    let mut config = ArcanConfig::default();
200→
201→    // Layer 1: global config
202→    if let Some(global_path) = global_config_path() {
203→        if let Some(global) = load_config_file(&global_path) {
204→            config.merge(&global);
205→        }
206→    }
207→
208→    // Layer 2: project-local config
209→    let local_path = local_config_path(data_dir);
210→    if let Some(local) = load_config_file(&local_path) {
211→        config.merge(&local);
212→    }
213→
214→    config
215→}
