217→/// Load a single TOML config file. Returns None if file doesn't exist or is invalid.
218→fn load_config_file(path: &Path) -> Option<ArcanConfig> {
219→    let content = std::fs::read_to_string(path).ok()?;
220→    toml::from_str(&content).ok()
221→}
222→
223→/// Save config to the project-local config file.
224→pub fn save_config(data_dir: &Path, config: &ArcanConfig) -> anyhow::Result<()> {
225→    let path = local_config_path(data_dir);
226→    std::fs::create_dir_all(data_dir)?;
227→    let content = toml::to_string_pretty(config)
228→        .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
229→    std::fs::write(&path, content)?;
230→    Ok(())
231→}
