233→/// Resolve the final config by applying env vars and CLI overrides on top.
234→pub fn resolve(
235→    config: &ArcanConfig,
236→    cli_provider: Option<&str>,
237→    cli_model: Option<&str>,
238→    cli_port: Option<u16>,
239→    cli_max_iterations: Option<u32>,
240→    cli_approval_timeout: Option<u64>,
241→) -> ResolvedConfig {
242→    // Provider: CLI > env > config > ""
243→    let provider = cli_provider
244→        .map(String::from)
245→        .or_else(|| std::env::var("ARCAN_PROVIDER").ok())
246→        .or_else(|| config.defaults.provider.clone())
247→        .unwrap_or_default();
248→
249→    // Model: CLI > env > provider-specific config > defaults config > None
250→    let model = cli_model
251→        .map(String::from)
252→        .or_else(|| std::env::var("ARCAN_MODEL").ok())
253→        .or_else(|| {
254→            config
255→                .providers
256→                .get(&provider)
257→                .and_then(|pc| pc.model.clone())
258→        })
259→        .or_else(|| config.defaults.model.clone());
260→
261→    // Port: CLI > env > config > 3000
262→    let port = cli_port
263→        .or_else(|| {
264→            std::env::var("ARCAN_PORT")
265→                .ok()
266→                .and_then(|s| s.parse().ok())
267→        })
268→        .or(config.defaults.port)
269→        .unwrap_or(3000);
270→
271→    // Max iterations: CLI > config > 10
272→    let max_iterations = cli_max_iterations
273→        .or(config.agent.max_iterations)
274→        .unwrap_or(10);
275→
276→    // Approval timeout: CLI > config > 300
277→    let approval_timeout = cli_approval_timeout
278→        .or(config.agent.approval_timeout)
279→        .unwrap_or(300);
280→
281→    // Provider-specific config section
282→    let provider_config = config.providers.get(&provider).cloned();
283→
284→    ResolvedConfig {
285→        provider,
286→        model,
287→        port,
288→        max_iterations,
289→        approval_timeout,
290→        provider_config,
291→    }
292→}
