102→/// Ensure a daemon is running on the given port.
103→///
104→/// 1. Probe `GET /health`. If healthy, return immediately.
105→/// 2. Check `daemon.pid` — if process alive but health fails, wait briefly.
106→/// 3. If PID is stale, remove PID file and proceed.
107→/// 4. Spawn `arcan serve` as a detached child process.
108→/// 5. Poll `/health` until it succeeds (up to ~12 s).
109→pub async fn ensure_daemon(
110→    data_dir: &Path,
111→    port: u16,
112→    provider: Option<&str>,
113→    model: Option<&str>,
114→) -> anyhow::Result<String> {
115→    let base_url = format!("http://127.0.0.1:{port}");
116→
117→    if is_daemon_healthy(&base_url).await {
118→        tracing::info!("Daemon already running on {base_url}");
119→        return Ok(base_url);
120→    }
121→
122→    // Check PID file before spawning a new daemon.
123→    if let Some(pid) = check_existing_pid(data_dir) {
124→        // Process is alive but health check failed — it might be starting up.
125→        tracing::info!(pid, "Daemon process alive, waiting for health...");
126→        let delay = Duration::from_millis(200);
127→        for _ in 0..15 {
128→            tokio::time::sleep(delay).await;
129→            if is_daemon_healthy(&base_url).await {
130→                tracing::info!("Existing daemon became healthy on {base_url}");
131→                return Ok(base_url);
132→            }
133→        }
134→        // Still not healthy after 3s — the process might be stuck.
135→        tracing::warn!(
136→            pid,
137→            "Daemon process alive but not healthy after 3s, spawning new"
138→        );
139→    }
140→
141→    tracing::info!("Starting daemon on port {port}...");
142→
143→    fs::create_dir_all(data_dir)?;
144→    let log_file = fs::File::create(data_dir.join("daemon.log"))?;
145→    let stderr_log = log_file.try_clone()?;
146→
147→    // Resolve the current executable so `arcan serve` uses the same binary.
148→    let exe = std::env::current_exe()?;
149→
150→    let port_str = port.to_string();
151→    let dir_str = data_dir.to_string_lossy().to_string();
152→    let mut args = vec!["serve", "--port", &port_str, "--data-dir", &dir_str];
153→    if let Some(p) = provider {
154→        args.extend(["--provider", p]);
155→    }
156→    if let Some(m) = model {
157→        args.extend(["--model", m]);
158→    }
159→
160→    let child = std::process::Command::new(exe)
161→        .args(&args)
162→        .stdout(log_file)
163→        .stderr(stderr_log)
164→        .stdin(std::process::Stdio::null())
165→        .spawn()?;
166→
167→    // Write PID for later inspection / cleanup.
168→    fs::write(data_dir.join("daemon.pid"), child.id().to_string())?;
169→
170→    // Poll health endpoint.
171→    let max_retries = 60;
172→    let delay = Duration::from_millis(200);
173→    for i in 0..max_retries {
174→        tokio::time::sleep(delay).await;
175→        if is_daemon_healthy(&base_url).await {
176→            tracing::info!("Daemon healthy after {} ms", (i + 1) * 200);
177→            return Ok(base_url);
178→        }
179→    }
180→
181→    anyhow::bail!(
182→        "Daemon failed to become healthy within {}s. Check {}/daemon.log for details.",
183→        max_retries * 200 / 1000,
184→        data_dir.display()
185→    );
186→}
