121→pub fn create_canonical_router(runtime: Arc<KernelRuntime>) -> Router {
122→    let state = CanonicalState { runtime };
123→    Router::new()
124→        .route("/health", get(health))
125→        .route("/sessions", get(list_sessions).post(create_session))
126→        .route("/sessions/{session_id}/runs", post(run_session))
127→        .route("/sessions/{session_id}/state", get(get_state))
128→        .route("/sessions/{session_id}/events", get(list_events))
129→        .route("/sessions/{session_id}/events/stream", get(stream_events))
130→        .route(
131→            "/sessions/{session_id}/branches",
132→            post(create_branch).get(list_branches),
133→        )
134→        .route(
135→            "/sessions/{session_id}/branches/{branch_id}/merge",
136→            post(merge_branch),
137→        )
138→        .route(
139→            "/sessions/{session_id}/approvals/{approval_id}",
140→            post(resolve_approval),
141→        )
142→        .with_state(state)
143→}
