214→async fn run_session(
215→    Path(session_id): Path<String>,
216→    State(state): State<CanonicalState>,
217→    Json(request): Json<RunRequest>,
218→) -> Result<Json<RunResponse>, (StatusCode, Json<serde_json::Value>)> {
219→    let session_id = SessionId::from_string(session_id);
220→    let branch = request
221→        .branch
222→        .as_deref()
223→        .map(BranchId::from_string)
224→        .unwrap_or_else(BranchId::main);
225→    if !state.runtime.session_exists(&session_id) {
226→        state
227→            .runtime
228→            .create_session_with_id(
229→                session_id.clone(),
230→                "arcan",
231→                PolicySet::default(),
232→                ModelRouting::default(),
233→            )
234→            .await
235→            .map_err(internal_error)?;
236→    }
237→    let proposed_tool = request
238→        .proposed_tool
239→        .map(|tool| ToolCall::new(tool.tool_name, tool.input, tool.requested_capabilities));
240→
241→    let tick = state
242→        .runtime
243→        .tick_on_branch(
244→            &session_id,
245→            &branch,
246→            TickInput {
247→                objective: request.objective,
248→                proposed_tool,
249→            },
250→        )
251→        .await
252→        .map_err(internal_error)?;
253→
254→    persist_last_session_hint(state.runtime.as_ref(), &tick.session_id).await;
255→
256→    Ok(Json(RunResponse {
257→        session_id: tick.session_id,
258→        mode: tick.mode,
259→        state: tick.state,
260→        events_emitted: tick.events_emitted,
261→        last_sequence: tick.last_sequence,
262→    }))
263→}
