18→/// Launch the TUI, connecting to an already-running daemon.
19→///
20→/// This sets up the terminal, runs the event loop, and restores the terminal on
21→/// exit. The caller is responsible for ensuring the daemon is reachable at
22→/// `base_url` before calling this function.
23→pub async fn run_tui(base_url: String, session_id: String) -> anyhow::Result<()> {
24→    // Setup terminal
25→    enable_raw_mode()?;
26→    let mut stdout = io::stdout();
27→    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
28→    let backend = CrosstermBackend::new(stdout);
29→    let mut terminal = Terminal::new(backend)?;
30→
31→    // Create app and run
32→    let config = NetworkConfig {
33→        base_url,
34→        session_id,
35→    };
36→    let mut app = App::new(config);
37→    let res = app.run(&mut terminal).await;
38→
39→    // Restore terminal
40→    disable_raw_mode()?;
41→    execute!(
42→        terminal.backend_mut(),
43→        LeaveAlternateScreen,
44→        DisableMouseCapture
45→    )?;
46→    terminal.show_cursor()?;
47→
48→    if let Err(ref err) = res {
49→        eprintln!("{err:?}");
50→    }
51→
52→    res
53→}
