  43→    async fn post_execute(&self, session_id: String, _tool_name: String) {
  44→        // We skip memory tools since they don't modify the FS directly, and bash since we might want more granular control, but for now we trace everything.
  45→        let sess_id = SessionId::from_string(session_id.clone());
  46→        let branch_id = BranchId::from_string("main");
  47→
  48→        let events = match self
  49→            .journal
  50→            .read(EventQuery::new().session(lago_core::SessionId::from_string(session_id)))
  51→            .await
  52→        {
  53→            Ok(events) => events,
  54→            Err(e) => {
  55→                tracing::warn!(%e, "LakeFsObserver: failed to read journal");
  56→                return;
  57→            }
  58→        };
  59→
  60→        let mut proj = ManifestProjection::new();
  61→        for e in events {
  62→            if e.branch_id == branch_id {
  63→                let _ = proj.on_event(&e);
  64→            }
  65→        }
  66→
  67→        let current_manifest = proj.manifest().clone();
  68→
  69→        let new_manifest =
  70→            match lago_fs::snapshot(&self.workspace_root, &current_manifest, &self.blob_store) {
  71→                Ok(m) => m,
  72→                Err(e) => {
  73→                    tracing::warn!(%e, "LakeFsObserver: failed to snapshot workspace");
  74→                    return;
  75→                }
  76→            };
  77→
  78→        let diffs = lago_fs::diff(&current_manifest, &new_manifest);
  79→        if diffs.is_empty() {
  80→            return;
  81→        }
  82→
  83→        tracing::info!(
  84→            diff_count = diffs.len(),
  85→            "LakeFsObserver: workspace changed, emitting events"
  86→        );
  87→
  88→        for diff in diffs {
  89→            let payload = match diff {
  90→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
  91→                    path,
  92→                    blob_hash: entry.blob_hash.into(),
  93→                    size_bytes: entry.size_bytes,
  94→                    content_type: entry.content_type,
  95→                },
  96→                DiffEntry::Modified {
  97→                    path, new: entry, ..
  98→                } => EventPayload::FileWrite {
  99→                    path,
 100→                    blob_hash: entry.blob_hash.into(),
 101→                    size_bytes: entry.size_bytes,
 102→                    content_type: entry.content_type,
 103→                },
 104→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
 105→            };
 106→
 107→            let envelope = EventEnvelope {
 108→                event_id: EventId::new(),
 109→                session_id: sess_id.clone(),
 110→                branch_id: branch_id.clone(),
 111→                run_id: None,
 112→                seq: 0,
 113→                timestamp: EventEnvelope::now_micros(),
 114→                parent_id: None,
 115→                payload,
 116→                metadata: std::collections::HashMap::new(),
 117→                schema_version: 1,
 118→            };
 119→
 120→            if let Err(e) = self.journal.append(envelope).await {
 121→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
 122→            }
 123→        }
 124→    }
 125→}
