 247→async fn shutdown_signal() {
 248→    let ctrl_c = tokio::signal::ctrl_c();
 249→
 250→    #[cfg(unix)]
 251→    {
 252→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
 253→            .expect("failed to install SIGTERM handler");
 254→        tokio::select! {
 255→            _ = ctrl_c => {},
 256→            _ = sigterm.recv() => {},
 257→        }
 258→    }
 259→
 260→    #[cfg(not(unix))]
 261→    {
 262→        ctrl_c.await.ok();
 263→    }
 264→
 265→    tracing::info!("Received shutdown signal, draining connections...");
 266→}
