 277→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
 278→    let path = data_dir.join("last_session");
 279→    let raw = std::fs::read_to_string(path).ok()?;
 280→    let session = raw.trim();
 281→    if session.is_empty() {
 282→        None
 283→    } else {
 284→        Some(session.to_owned())
 285→    }
 286→}
