 288→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
 289→    std::fs::create_dir_all(data_dir)?;
 290→    std::fs::write(data_dir.join("last_session"), session)?;
 291→    Ok(())
 292→}
