 294→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
 295→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
 296→async fn resolve_session(
 297→    data_dir: &Path,
 298→    requested: Option<String>,
 299→    base_url: Option<&str>,
 300→) -> String {
 301→    if let Some(session) = requested {
 302→        return session;
 303→    }
 304→
 305→    if let Some(session) = read_last_session_hint(data_dir) {
 306→        return session;
 307→    }
 308→
 309→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
 310→    if let Some(url) = base_url {
 311→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
 312→            return session;
 313→        }
 314→    }
 315→
 316→    "default".to_owned()
 317→}
