 319→/// Try to create an OpenAI provider from stored OAuth credentials.
 320→fn try_openai_oauth_provider() -> Option<Arc<dyn Provider>> {
 321→    let tokens = arcan_provider::oauth::load_tokens("openai").ok()?;
 322→    let credential = Arc::new(arcan_provider::oauth::OAuthCredential::openai(tokens));
 323→    let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
 324→    let config = arcan_provider::openai::OpenAiConfig::from_oauth(credential, model.clone());
 325→    tracing::info!(%model, "Provider: OpenAI (OAuth)");
 326→    Some(Arc::new(
 327→        arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 328→    ))
 329→}
 330→
 331→/// Build provider from resolved configuration.
 332→fn build_provider(resolved: &ResolvedConfig) -> anyhow::Result<Arc<dyn Provider>> {
 333→    let pc = resolved.provider_config.as_ref();
 334→
 335→    match resolved.provider.as_str() {
 336→        "mock" => {
 337→            tracing::warn!("Provider: MockProvider (forced via config)");
 338→            Ok(Arc::new(MockProvider))
 339→        }
 340→        "openai" | "codex" | "openai-codex" => {
 341→            // Try OAuth credential first, then fall back to env var / resolved config.
 342→            if let Some(p) = try_openai_oauth_provider() {
 343→                return Ok(p);
 344→            }
 345→            let config = arcan_provider::openai::OpenAiConfig::openai_from_resolved(
 346→                resolved.model.as_deref(),
 347→                pc.and_then(|p| p.base_url.as_deref()),
 348→                pc.and_then(|p| p.max_tokens),
 349→            )?;
 350→            tracing::info!(model = %config.model, "Provider: OpenAI");
 351→            Ok(Arc::new(
 352→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 353→            ))
 354→        }
 355→        "ollama" => {
 356→            let config = arcan_provider::openai::OpenAiConfig::ollama_from_resolved(
 357→                resolved.model.as_deref(),
 358→                pc.and_then(|p| p.base_url.as_deref()),
 359→                pc.and_then(|p| p.max_tokens),
 360→                pc.and_then(|p| p.enable_streaming),
 361→            )?;
 362→            tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
 363→            Ok(Arc::new(
 364→                arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 365→            ))
 366→        }
 367→        "anthropic" => {
 368→            let config = AnthropicConfig::from_resolved(
 369→                resolved.model.as_deref(),
 370→                pc.and_then(|p| p.base_url.as_deref()),
 371→                pc.and_then(|p| p.max_tokens),
 372→            )?;
 373→            tracing::info!(model = %config.model, "Provider: Anthropic");
 374→            Ok(Arc::new(AnthropicProvider::new(config)))
 375→        }
 376→        // Auto-detect: try providers in order
 377→        _ => {
 378→            if let Ok(config) = AnthropicConfig::from_env() {
 379→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
 380→                Ok(Arc::new(AnthropicProvider::new(config)))
 381→            } else if let Some(p) = try_openai_oauth_provider() {
 382→                Ok(p)
 383→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
 384→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
 385→                Ok(Arc::new(
 386→                    arcan_provider::openai::OpenAiCompatibleProvider::new(config),
 387→                ))
 388→            } else {
 389→                tracing::warn!(
 390→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
 391→                );
 392→                Ok(Arc::new(MockProvider))
 393→            }
 394→        }
 395→    }
 396→}
