 398→fn run_serve(data_dir: &Path, resolved: &ResolvedConfig) -> anyhow::Result<()> {
 399→    let workspace_root = std::env::current_dir()?;
 400→
 401→    // --- Lago persistence ---
 402→    let journal_path = data_dir.join("journal.redb");
 403→    let blobs_path = data_dir.join("blobs");
 404→    std::fs::create_dir_all(&blobs_path)?;
 405→
 406→    tracing::info!(
 407→        workspace = %workspace_root.display(),
 408→        journal = %journal_path.display(),
 409→        blobs = %blobs_path.display(),
 410→        provider = %resolved.provider,
 411→        model = ?resolved.model,
 412→        port = resolved.port,
 413→        "Starting arcan"
 414→    );
 415→
 416→    let journal = RedbJournal::open(&journal_path)?;
 417→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
 418→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
 419→
 420→    // --- Policies ---
 421→    let fs_policy = FsPolicy::new(workspace_root.clone());
 422→    let sandbox_policy = SandboxPolicy {
 423→        workspace_root: workspace_root.clone(),
 424→        shell_enabled: true,
 425→        network: NetworkPolicy::AllowAll,
 426→        allowed_env: BTreeSet::new(),
 427→        max_execution_ms: 10_000,
 428→        max_stdout_bytes: 1024 * 1024,
 429→        max_stderr_bytes: 1024 * 1024,
 430→        max_processes: 10,
 431→        max_memory_mb: 512,
 432→    };
 433→
 434→    // --- Tools ---
 435→    let mut registry = ToolRegistry::default();
 436→    registry.register(ReadFileTool::new(fs_policy.clone()));
 437→    registry.register(WriteFileTool::new(fs_policy.clone()));
 438→    registry.register(ListDirTool::new(fs_policy.clone()));
 439→    registry.register(EditFileTool::new(fs_policy.clone()));
 440→    registry.register(GlobTool::new(fs_policy.clone()));
 441→    registry.register(GrepTool::new(fs_policy));
 442→
 443→    let runner = Box::new(LocalCommandRunner);
 444→    registry.register(BashTool::new(sandbox_policy, runner));
 445→
 446→    let memory_dir = data_dir.join("memory");
 447→    std::fs::create_dir_all(&memory_dir)?;
 448→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
 449→    registry.register(WriteMemoryTool::new(memory_dir));
 450→
 451→    // --- Governed memory tools (event-sourced via Lago) ---
 452→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
 453→    registry.register(MemoryQueryTool::new(memory_projection));
 454→    registry.register(MemoryProposeTool::new(journal.clone()));
 455→    registry.register(MemoryCommitTool::new(journal.clone()));
 456→
 457→    // --- Provider ---
 458→    let provider = build_provider(resolved)?;
 459→
 460→    // --- Canonical aiOS runtime adapters ---
 461→    let event_store: Arc<dyn EventStorePort> =
 462→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
 463→    // Shared handle: starts empty, filled after runtime creation.
 464→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
 465→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::new(
 466→        provider,
 467→        registry.definitions(),
 468→        streaming_sender.clone(),
 469→    ));
 470→    let observer = Arc::new(LakeFsObserver {
 471→        workspace_root: workspace_root.clone(),
 472→        journal: journal.clone(),
 473→        blob_store: _blob_store,
 474→    });
 475→    let tool_harness: Arc<dyn ToolHarnessPort> =
 476→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
 477→    let policy_gate: Arc<dyn PolicyGatePort> =
 478→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
 479→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
 480→
 481→    let runtime = Arc::new(KernelRuntime::new(
 482→        RuntimeConfig::new(data_dir.to_path_buf()),
 483→        event_store,
 484→        provider_adapter,
 485→        tool_harness,
 486→        approvals,
 487→        policy_gate,
 488→    ));
 489→
 490→    // Wire the broadcast sender now that the runtime exists.
 491→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
 492→
 493→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
 494→    let data_dir_owned = data_dir.to_path_buf();
 495→    let port = resolved.port;
 496→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
 497→        .enable_all()
 498→        .build()?;
 499→
 500→    tokio_runtime.block_on(async move {
 501→        // --- HTTP Server ---
 502→        let router = create_canonical_router(runtime);
 503→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
 504→        let listener = TcpListener::bind(addr).await?;
 505→
 506→        tracing::info!(%addr, "Listening");
 507→        axum::serve(listener, router)
 508→            .with_graceful_shutdown(shutdown_signal())
 509→            .await?;
 510→
 511→        // Clean up PID file on graceful shutdown.
 512→        daemon::remove_pid_file(&data_dir_owned);
 513→
 514→        tracing::info!("Server shut down gracefully");
 515→        Ok(())
 516→    })
 517→}
