 519→async fn run_chat(
 520→    data_dir: PathBuf,
 521→    resolved: &ResolvedConfig,
 522→    session: Option<String>,
 523→    url: Option<String>,
 524→) -> anyhow::Result<()> {
 525→    // Ensure daemon is running first to avoid redb lock conflicts.
 526→    let base_url = match url {
 527→        Some(u) => u,
 528→        None => {
 529→            daemon::ensure_daemon(
 530→                &data_dir,
 531→                resolved.port,
 532→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 533→                resolved.model.as_deref(),
 534→            )
 535→            .await?
 536→        }
 537→    };
 538→
 539→    // Resolve session via API (no direct journal access).
 540→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
 541→    tracing::info!(session = %session, "launching TUI");
 542→
 543→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
 544→        tracing::warn!(%error, "failed to persist last_session hint");
 545→    }
 546→
 547→    arcan_tui::run_tui(base_url, session).await
 548→}
