 551→    data_dir: PathBuf,
 552→    resolved: &ResolvedConfig,
 553→    message: String,
 554→    session: Option<String>,
 555→    url: Option<String>,
 556→    json_output: bool,
 557→) -> anyhow::Result<()> {
 558→    // Ensure daemon is running first.
 559→    let base_url = match url {
 560→        Some(u) => u,
 561→        None => {
 562→            daemon::ensure_daemon(
 563→                &data_dir,
 564→                resolved.port,
 565→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 566→                resolved.model.as_deref(),
 567→            )
 568→            .await?
 569→        }
 570→    };
 571→
 572→    // Resolve session via API (no direct journal access).
 573→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
