 594→fn run_config(data_dir: &Path, action: ConfigAction) -> anyhow::Result<()> {
 595→    match action {
 596→        ConfigAction::Init => {
 597→            let path = config::local_config_path(data_dir);
 598→            if path.exists() {
 599→                println!("Config file already exists: {}", path.display());
 600→            } else {
 601→                std::fs::create_dir_all(data_dir)?;
 602→                std::fs::write(&path, config::default_config_content())?;
 603→                println!("Created config: {}", path.display());
 604→            }
 605→        }
 606→        ConfigAction::Set { key, value } => {
 607→            let mut cfg = config::load_config(data_dir);
 608→            cfg.set_key(&key, &value)
 609→                .map_err(|e| anyhow::anyhow!("{e}"))?;
 610→            config::save_config(data_dir, &cfg)?;
 611→            println!("{key} = {value}");
 612→        }
 613→        ConfigAction::Get { key } => {
 614→            let cfg = config::load_config(data_dir);
 615→            match cfg.get_key(&key) {
 616→                Some(value) => println!("{value}"),
 617→                None => println!("(not set)"),
 618→            }
 619→        }
 620→        ConfigAction::List => {
 621→            let cfg = config::load_config(data_dir);
 622→            let content = toml::to_string_pretty(&cfg)
 623→                .map_err(|e| anyhow::anyhow!("failed to serialize config: {e}"))?;
 624→            if content.trim().is_empty()
 625→                || content.trim() == "[defaults]\n\n[agent]"
 626→                || content
 627→                    .lines()
 628→                    .all(|l| l.trim().is_empty() || l.starts_with('['))
 629→            {
 630→                println!("(no config values set)");
 631→                if let Some(path) = config::global_config_path() {
 632→                    println!("Global config: {}", path.display());
 633→                }
 634→                println!(
 635→                    "Local config:  {}",
 636→                    config::local_config_path(data_dir).display()
 637→                );
 638→            } else {
 639→                print!("{content}");
 640→            }
 641→        }
 642→    }
 643→    Ok(())
 644→}
