 666→
 667→    // Daemon status
 668→    let base_url = format!("http://127.0.0.1:{}", resolved.port);
 669→    match daemon::check_existing_pid(data_dir) {
 670→        Some(pid) => {
 671→            let client = reqwest::Client::builder()
 672→                .timeout(std::time::Duration::from_secs(2))
 673→                .build()?;
 674→            let healthy = matches!(
 675→                client.get(format!("{base_url}/health")).send().await,
 676→                Ok(resp) if resp.status().is_success()
 677→            );
 678→            if healthy {
 679→                println!("Daemon:     running (PID {pid}, healthy)");
 680→            } else {
 681→                println!("Daemon:     running (PID {pid}, NOT healthy)");
 682→            }
 683→        }
 684→        None => {
 685→            println!("Daemon:     not running");
 686→        }
 687→    }
 688→
 689→    // Last session
 690→    match read_last_session_hint(data_dir) {
 691→        Some(session) => println!("Session:    {session}"),
 692→        None => println!("Session:    (none)"),
 693→    }
 694→
 695→    // Config file locations
 696→    if let Some(global_path) = config::global_config_path() {
 697→        let exists = global_path.exists();
 698→        println!(
 699→            "Global cfg: {} {}",
 700→            global_path.display(),
 701→            if exists { "" } else { "(not found)" }
 702→        );
 703→    }
 704→    let local_path = config::local_config_path(data_dir);
 705→    let exists = local_path.exists();
 706→    println!(
 707→        "Local cfg:  {} {}",
 708→        local_path.display(),
 709→        if exists { "" } else { "(not found)" }
 710→    );
 711→
 712→    Ok(())
 713→}
