 715→#[allow(clippy::print_stderr)]
 716→fn run_login(provider: &str, device: bool, data_dir: &Path) -> anyhow::Result<()> {
 717→    // Normalize to canonical provider name for config persistence.
 718→    let canonical = match provider {
 719→        "codex" | "openai-codex" => "openai",
 720→        other => other,
 721→    };
 722→
 723→    match provider {
 724→        "openai" | "codex" | "openai-codex" => {
 725→            if device {
 726→                arcan_provider::oauth::device_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 727→            } else {
 728→                arcan_provider::oauth::pkce_login_openai().map_err(|e| anyhow::anyhow!("{e}"))?;
 729→            }
 730→        }
 731→        _ => {
 732→            return Err(anyhow::anyhow!(
 733→                "Unknown provider '{provider}'. Supported: openai"
 734→            ));
 735→        }
 736→    }
 737→
 738→    // Set the provider as the new default after successful login.
 739→    let mut file_config = config::load_config(data_dir);
 740→    file_config.set_key("provider", canonical).ok();
 741→    config::save_config(data_dir, &file_config)?;
 742→    eprintln!("Default provider set to '{canonical}'");
 743→
 744→    Ok(())
 745→}
