 747→#[allow(clippy::print_stdout)]
 748→async fn run_api(
 749→    data_dir: PathBuf,
 750→    resolved: &ResolvedConfig,
 751→    url: Option<String>,
 752→    output: Option<PathBuf>,
 753→) -> anyhow::Result<()> {
 754→    // If --output is given, write the spec to a file and exit.
 755→    if let Some(path) = output {
 756→        let spec = arcand::canonical::openapi_spec();
 757→        let json = serde_json::to_string_pretty(&spec)?;
 758→        std::fs::write(&path, &json)?;
 759→        println!("OpenAPI spec written to {}", path.display());
 760→        return Ok(());
 761→    }
 762→
 763→    // Ensure daemon is running.
 764→    let base_url = match url {
 765→        Some(u) => u,
 766→        None => {
 767→            daemon::ensure_daemon(
 768→                &data_dir,
 769→                resolved.port,
 770→                Some(resolved.provider.as_str()).filter(|s| !s.is_empty()),
 771→                resolved.model.as_deref(),
 772→            )
 773→            .await?
 774→        }
 775→    };
 776→
 777→    let spec_url = format!("{base_url}/openapi.json");
 778→
 779→    // Check if openapi-tui is installed.
 780→    let has_tui = std::process::Command::new("which")
 781→        .arg("openapi-tui")
 782→        .stdout(std::process::Stdio::null())
 783→        .stderr(std::process::Stdio::null())
 784→        .status()
 785→        .is_ok_and(|s| s.success());
 786→
 787→    if has_tui {
 788→        println!("Launching openapi-tui with {spec_url}");
 789→        let status = std::process::Command::new("openapi-tui")
 790→            .args(["-i", &spec_url])
 791→            .status()?;
 792→        if !status.success() {
 793→            anyhow::bail!("openapi-tui exited with status {status}");
 794→        }
 795→    } else {
 796→        println!("OpenAPI spec available at: {spec_url}");
 797→        println!();
 798→        println!("To browse interactively, install openapi-tui:");
 799→        println!("  cargo install openapi-tui");
 800→        println!("  openapi-tui -i {spec_url}");
 801→        println!();
 802→        println!("Or fetch the spec directly:");
 803→        println!("  curl -s {spec_url} | jq .");
 804→    }
 805→
 806→    Ok(())
 807→}
