 809→#[allow(clippy::print_stderr)]
 810→fn run_logout(provider: &str, data_dir: &Path) -> anyhow::Result<()> {
 811→    // Normalize provider name for credential lookup.
 812→    let normalized = match provider {
 813→        "codex" | "openai-codex" => "openai",
 814→        other => other,
 815→    };
 816→    arcan_provider::oauth::remove_tokens(normalized).map_err(|e| anyhow::anyhow!("{e}"))?;
 817→
 818→    // Clear the default provider if it matches the one being logged out.
 819→    let mut file_config = config::load_config(data_dir);
 820→    if file_config.defaults.provider.as_deref() == Some(normalized) {
 821→        file_config.defaults.provider = None;
 822→        config::save_config(data_dir, &file_config)?;
 823→        eprintln!("Default provider cleared");
 824→    }
 825→
 826→    eprintln!("Logged out of {provider}");
 827→    Ok(())
 828→}
