 832→    let data_dir = resolve_data_dir(&cli.data_dir)?;
 833→
 834→    // Load layered config.
 835→    let file_config = config::load_config(&data_dir);
 836→
 837→    match cli.command {
 838→        Some(Command::Serve {
 839→            max_iterations,
 840→            approval_timeout,
 841→        }) => {
