 860→            let log_dir = data_dir.join("logs");
 861→            std::fs::create_dir_all(&log_dir)?;
 862→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
 863→            tracing_subscriber::fmt()
 864→                .with_writer(file_appender)
