  1→//! Non-interactive CLI runner for Arcan.
  2→//!
  3→//! Opens an SSE stream for real-time events, then POST /runs concurrently.
  4→//! Text deltas, tool lifecycle, and errors render to stdout as they arrive.
  5→
  6→use std::io::Write;
  7→
  8→use futures_util::StreamExt;
  9→use reqwest::Client;
 10→use reqwest_eventsource::{Event as SseEvent, EventSource};
 11→use serde::Deserialize;
 12→
 13→/// Subset of EventRecord fields we care about for CLI output.
 14→#[derive(Debug, Deserialize)]
 15→struct EventRecord {
 16→    kind: EventKind,
 17→    #[serde(default)]
 18→    sequence: u64,
 19→}
 20→
 21→/// Subset of EventKind variants for display purposes.
 22→/// Uses the same `#[serde(tag = "type")]` format as the canonical EventKind.
 23→#[derive(Debug, Deserialize)]
 24→#[serde(tag = "type")]
 25→enum EventKind {
 26→    TextDelta {
 27→        delta: String,
 28→    },
 29→    AssistantTextDelta {
 30→        delta: String,
 31→    },
 32→    Message {
 33→        content: String,
 34→    },
 35→    ToolCallRequested {
 36→        tool_name: String,
 37→    },
 38→    ToolCallStarted {
 39→        tool_name: String,
 40→    },
 41→    ToolCallCompleted {
 42→        tool_name: String,
 43→    },
 44→    ToolCallFailed {
 45→        tool_name: String,
 46→        error: String,
 47→    },
 48→    RunFinished {},
 49→    RunErrored {
 50→        error: String,
 51→    },
 52→    #[serde(other)]
 53→    Other,
 54→}
 55→
 56→/// Run a single message against the daemon and print the response to stdout.
 57→///
 58→/// Opens an SSE stream at `/events/stream` before firing `/runs`, so events
 59→/// (including ephemeral streaming text deltas) render in real time.
 60→pub async fn run_cli(
 61→    base_url: &str,
 62→    session_id: &str,
 63→    message: &str,
 64→    json_output: bool,
 65→    model: Option<&str>,
 66→) -> anyhow::Result<i32> {
 67→    let client = Client::new();
 68→
 69→    // Ensure session exists (creates if needed via POST /sessions).
 70→    let mut session_body = serde_json::json!({ "session_id": session_id });
 71→    if let Some(m) = model {
 72→        session_body["model_routing"] = serde_json::json!({
 73→            "primary_model": m,
 74→        });
 75→    }
 76→    client
 77→        .post(format!("{base_url}/sessions"))
 78→        .json(&session_body)
 79→        .send()
 80→        .await?;
 81→
 82→    // Get the current event cursor so we only see new events.
 83→    let events_response = client
 84→        .get(format!(
 85→            "{base_url}/sessions/{session_id}/events?limit=10000"
 86→        ))
 87→        .send()
 88→        .await?;
 89→    let cursor = if events_response.status().is_success() {
 90→        let body: serde_json::Value = events_response.json().await?;
 91→        body.get("events")
 92→            .and_then(|v| v.as_array())
 93→            .and_then(|arr| arr.last())
 94→            .and_then(|e| e.get("sequence"))
 95→            .and_then(serde_json::Value::as_u64)
 96→            .unwrap_or(0)
 97→    } else {
 98→        0
 99→    };
100→
101→    // Open SSE stream before firing the run.
102→    let stream_url =
103→        format!("{base_url}/sessions/{session_id}/events/stream?cursor={cursor}&format=canonical");
104→    let mut event_source = EventSource::get(&stream_url);
105→
106→    // Fire the run concurrently (don't await completion before reading SSE).
107→    let run_url = format!("{base_url}/sessions/{session_id}/runs");
108→    let run_body = serde_json::json!({ "objective": message });
109→    let run_client = client.clone();
110→    let run_handle = tokio::spawn(async move {
111→        let result = run_client.post(&run_url).json(&run_body).send().await;
112→        match result {
113→            Ok(resp) if !resp.status().is_success() => {
114→                let status = resp.status();
115→                let body = resp.text().await.unwrap_or_default();
116→                Err(anyhow::anyhow!("Run request failed ({status}): {body}"))
117→            }
118→            Ok(_) => Ok(()),
119→            Err(e) => Err(anyhow::anyhow!("Run request failed: {e}")),
120→        }
121→    });
122→
123→    let mut exit_code = 0;
124→    let mut stdout = std::io::stdout().lock();
125→    // Track whether we've received ephemeral streaming text (sequence 0).
126→    // If so, we skip persisted text events to avoid duplicate output.
127→    let mut saw_streaming_text = false;
128→
129→    // Read SSE events as they arrive.
130→    while let Some(event) = event_source.next().await {
131→        match event {
132→            Ok(SseEvent::Open) => {}
133→            Ok(SseEvent::Message(msg)) => {
134→                if json_output {
135→                    let _ = writeln!(stdout, "{}", msg.data);
136→                    let _ = stdout.flush();
137→                }
138→
139→                let Ok(record) = serde_json::from_str::<EventRecord>(&msg.data) else {
140→                    continue;
141→                };
142→
143→                if !json_output {
144→                    match &record.kind {
145→                        EventKind::TextDelta { delta }
146→                        | EventKind::AssistantTextDelta { delta } => {
147→                            if record.sequence == 0 {
148→                                // Ephemeral streaming delta — display immediately.
149→                                saw_streaming_text = true;
150→                                let _ = write!(stdout, "{delta}");
151→                                let _ = stdout.flush();
152→                            } else if !saw_streaming_text {
153→                                // Persisted delta, but only show if we didn't
154→                                // already see streaming text.
155→                                let _ = write!(stdout, "{delta}");
156→                                let _ = stdout.flush();
157→                            }
158→                            // else: skip persisted duplicate
159→                        }
160→                        EventKind::Message { content } => {
161→                            if !saw_streaming_text {
162→                                let _ = write!(stdout, "{content}");
163→                                let _ = stdout.flush();
164→                            }
165→                        }
166→                        EventKind::ToolCallRequested { tool_name } => {
167→                            let _ = writeln!(stdout, "\n[tool: {tool_name}] requested");
168→                        }
169→                        EventKind::ToolCallStarted { tool_name } => {
170→                            let _ = writeln!(stdout, "[tool: {tool_name}] started");
171→                        }
172→                        EventKind::ToolCallCompleted { tool_name } => {
173→                            let _ = writeln!(stdout, "[tool: {tool_name}] OK");
174→                        }
175→                        EventKind::ToolCallFailed { tool_name, error } => {
176→                            let _ = writeln!(stdout, "[tool: {tool_name}] ERROR: {error}");
177→                        }
178→                        EventKind::RunFinished {} => {
179→                            let _ = writeln!(stdout);
180→                            event_source.close();
181→                            break;
182→                        }
183→                        EventKind::RunErrored { error } => {
184→                            let _ = writeln!(stdout, "\nERROR: {error}");
185→                            exit_code = 1;
186→                            event_source.close();
187→                            break;
188→                        }
189→                        EventKind::Other => {}
190→                    }
191→                }
192→
193→                // In JSON mode, also detect run termination events.
194→                if json_output {
195→                    match &record.kind {
196→                        EventKind::RunFinished {} => {
197→                            event_source.close();
198→                            break;
199→                        }
200→                        EventKind::RunErrored { .. } => {
201→                            exit_code = 1;
202→                            event_source.close();
203→                            break;
204→                        }
205→                        _ => {}
206→                    }
207→                }
208→            }
209→            Err(_) => {
210→                // SSE connection closed or errored — stop reading.
211→                break;
212→            }
213→        }
214→    }
215→
216→    // Ensure the run request completed (surface errors).
217→    if let Err(e) = run_handle.await? {
218→        // Only report run errors if we didn't already get a RunErrored event.
219→        if exit_code == 0 {
220→            let _ = writeln!(stdout, "\nERROR: {e}");
221→            exit_code = 1;
222→        }
223→    }
224→
225→    Ok(exit_code)
226→}
