 12→#[derive(Debug, PartialEq, Eq)]
 13→enum ModelCommand {
 14→    ShowCurrent,
 15→    Set {
 16→        provider: String,
 17→        model: Option<String>,
 18→    },
 19→}
 20→
 21→fn parse_model_command(message: &str) -> Result<Option<ModelCommand>, String> {
 22→    let trimmed = message.trim();
 23→    if !trimmed.starts_with("/model") {
 24→        return Ok(None);
 25→    }
 26→
 27→    let remainder = trimmed.trim_start_matches("/model").trim();
 28→    if remainder.is_empty() {
 29→        return Ok(Some(ModelCommand::ShowCurrent));
 30→    }
 31→
 32→    if remainder.contains(char::is_whitespace) {
 33→        return Err("Usage: /model | /model <provider> | /model <provider>:<model>".to_string());
 34→    }
 35→
 36→    if let Some((provider, model)) = remainder.split_once(':') {
 37→        if provider.is_empty() || model.is_empty() {
 38→            return Err("Usage: /model <provider>:<model> (both values are required)".to_string());
 39→        }
 40→        return Ok(Some(ModelCommand::Set {
 41→            provider: provider.to_string(),
 42→            model: Some(model.to_string()),
 43→        }));
 44→    }
 45→
 46→    Ok(Some(ModelCommand::Set {
 47→        provider: remainder.to_string(),
 48→        model: None,
 49→    }))
 50→}
 51→
 52→pub struct App {
 53→    pub state: AppState,
 54→    pub should_quit: bool,
 55→    pub client: Arc<NetworkClient>,
 56→    pub event_rx: mpsc::Receiver<AgentEvent>,
 57→}
 58→
 59→impl App {
 60→    pub fn new(config: NetworkConfig) -> Self {
 61→        let client = Arc::new(NetworkClient::new(config));
 62→        let (tx, rx) = mpsc::channel(100);
 63→
 64→        // Spawn network listener
 65→        let listener_client = client.clone();
 66→        tokio::spawn(async move {
 67→            if let Err(e) = listener_client.listen_events(tx).await {
 68→                tracing::error!("Event listener ended: {}", e);
 69→            }
 70→        });
 71→
 72→        Self {
 73→            state: AppState::new(),
 74→            should_quit: false,
 75→            client,
 76→            event_rx: rx,
 77→        }
 78→    }
 79→
 80→    fn push_system_alert(&mut self, text: impl Into<String>) {
 81→        self.state.blocks.push(UiBlock::SystemAlert {
 82→            text: text.into(),
 83→            timestamp: Utc::now(),
 84→        });
 85→    }
 86→
 87→    async fn handle_model_command(&mut self, message: &str) -> bool {
 88→        let parsed = match parse_model_command(message) {
 89→            Ok(command) => command,
 90→            Err(usage) => {
 91→                self.push_system_alert(usage);
 92→                return true;
 93→            }
 94→        };
 95→
 96→        let Some(command) = parsed else {
 97→            return false;
 98→        };
 99→
100→        match command {
101→            ModelCommand::ShowCurrent => match self.client.get_model().await {
102→                Ok(model) => self.push_system_alert(format!("Current model: {model}")),
103→                Err(err) => self.push_system_alert(format!("Failed to fetch model: {err}")),
104→            },
105→            ModelCommand::Set { provider, model } => {
106→                match self.client.set_model(&provider, model.as_deref()).await {
107→                    Ok(active_model) => {
108→                        self.push_system_alert(format!("Switched model: {active_model}"))
109→                    }
110→                    Err(err) => self.push_system_alert(format!("Failed to switch model: {err}")),
111→                }
112→            }
113→        }
114→
115→        true
116→    }
117→
118→    pub async fn run<B: Backend>(&mut self, terminal: &mut Terminal<B>) -> anyhow::Result<()>
119→    where
120→        B::Error: Send + Sync + 'static,
121→    {
122→        loop {
123→            // Draw UI
124→            terminal.draw(|f| ui::draw(f, &self.state))?;
125→
126→            // Process external AgentEvents non-blocking
127→            while let Ok(event) = self.event_rx.try_recv() {
128→                self.state.apply_event(event);
129→            }
130→
131→            // Handle UI events non-blocking
132→            if event::poll(Duration::from_millis(50))? {
133→                if let Event::Key(key) = event::read()? {
134→                    if key.kind == KeyEventKind::Press {
135→                        match key.code {
136→                            KeyCode::Esc => self.should_quit = true,
137→                            KeyCode::Char('c')
138→                                if key
139→                                    .modifiers
140→                                    .contains(crossterm::event::KeyModifiers::CONTROL) =>
141→                            {
142→                                self.should_quit = true;
143→                            }
144→                            KeyCode::Char(c) => {
145→                                self.state.input_buffer.push(c);
146→                            }
147→                            KeyCode::Backspace => {
148→                                self.state.input_buffer.pop();
149→                            }
150→                            KeyCode::Enter => {
151→                                let msg = self.state.input_buffer.trim().to_string();
152→                                if !msg.is_empty() {
153→                                    if msg == "/clear" {
154→                                        self.state.blocks.clear();
155→                                        self.state.streaming_text = None;
156→                                        self.state.is_busy = false;
157→                                    } else if self.handle_model_command(&msg).await {
158→                                    } else if msg.starts_with("/approve") {
159→                                        let parts: Vec<&str> = msg.split_whitespace().collect();
160→                                        if parts.len() >= 3 {
161→                                            let approval_id = parts[1].to_string();
162→                                            let decision = match parts[2]
163→                                                .to_ascii_lowercase()
164→                                                .as_str()
165→                                            {
166→                                                "yes" | "y" | "approved" | "approve" => {
167→                                                    "approved".to_string()
168→                                                }
169→                                                "no" | "n" | "denied" | "deny" => {
170→                                                    "denied".to_string()
171→                                                }
172→                                                invalid => {
173→                                                    tracing::warn!(
174→                                                        "Invalid approval decision '{}'. Use yes/no.",
175→                                                        invalid
176→                                                    );
177→                                                    self.state.input_buffer.clear();
178→                                                    continue;
179→                                                }
180→                                            };
181→                                            let reason = if parts.len() > 3 {
182→                                                Some(parts[3..].join(" "))
183→                                            } else {
184→                                                None
185→                                            };
186→
187→                                            let submit_client = self.client.clone();
188→                                            tokio::spawn(async move {
189→                                                if let Err(e) = submit_client
190→                                                    .submit_approval(
191→                                                        &approval_id,
192→                                                        &decision,
193→                                                        reason.as_deref(),
194→                                                    )
195→                                                    .await
196→                                                {
197→                                                    tracing::error!("Submit approval error: {}", e);
198→                                                }
199→                                            });
200→                                        } else {
201→                                            tracing::warn!(
202→                                                "Invalid /approve syntax. Use: /approve <id> <yes|no> [reason]"
203→                                            );
204→                                        }
205→                                    } else {
206→                                        self.state.is_busy = true;
207→                                        self.state.blocks.push(UiBlock::HumanMessage {
208→                                            text: msg.clone(),
209→                                            timestamp: Utc::now(),
210→                                        });
211→                                        let submit_client = self.client.clone();
212→                                        tokio::spawn(async move {
213→                                            if let Err(e) =
214→                                                submit_client.submit_run(&msg, None).await
215→                                            {
216→                                                tracing::error!("Submit error: {}", e);
217→                                            }
218→                                        });
219→                                    }
220→                                    self.state.input_buffer.clear();
221→                                }
222→                            }
223→                            _ => {}
224→                        }
225→                    }
226→                }
227→            }
228→
229→            if self.should_quit {
230→                break;
231→            }
232→        }
233→        Ok(())
234→    }
235→}
