  4→/// Pure logical representation of the UI state.
  5→/// This model has zero dependency on ratatui or IO, making it easily testable.
  6→#[derive(Debug, Default)]
  7→pub struct AppState {
  8→    pub session_id: Option<String>,
  9→    pub current_branch: String,
 10→
 11→    /// The conversation history (messages, tool executions, errors)
 12→    pub blocks: Vec<UiBlock>,
 13→
 14→    /// Pending text delta buffer (assistant is typing)
 15→    pub streaming_text: Option<String>,
 16→
 17→    /// User input string
 18→    pub input_buffer: String,
 19→
 20→    /// True if the UI is blocked waiting for user approval of a policy intervention
 21→    pub pending_approval: Option<ApprovalRequest>,
 22→
 23→    /// Tracks if we're currently fetching from daemon
 24→    pub is_busy: bool,
 25→}
