 66→
 67→impl AppState {
 68→    pub fn new() -> Self {
 69→        Self {
 70→            session_id: None,
 71→            current_branch: "main".to_string(),
 72→            blocks: Vec::new(),
 73→            streaming_text: None,
 74→            input_buffer: String::new(),
 75→            pending_approval: None,
 76→            is_busy: false,
 77→        }
 78→    }
 79→
 80→    /// Process a raw AgentEvent from the daemon and mutate the view state.
 81→    pub fn apply_event(&mut self, event: AgentEvent) {
 82→        let now = Utc::now();
 83→        match event {
 84→            AgentEvent::RunStarted { .. } => {
 85→                self.is_busy = true;
 86→                self.streaming_text = None;
 87→            }
 88→            AgentEvent::TextDelta { delta, .. } => {
 89→                if let Some(mut text) = self.streaming_text.take() {
 90→                    text.push_str(&delta);
 91→                    self.streaming_text = Some(text);
 92→                } else {
 93→                    self.streaming_text = Some(delta);
 94→                }
 95→            }
 96→            AgentEvent::ToolCallRequested { call, .. } => {
 97→                // Flush streaming text if it exists (model stopped reasoning, started acting)
 98→                if let Some(text) = self.streaming_text.take() {
 99→                    self.blocks.push(UiBlock::AssistantMessage {
100→                        text,
101→                        timestamp: now,
102→                    });
103→                }
104→
105→                self.blocks.push(UiBlock::ToolExecution {
106→                    call_id: call.call_id,
107→                    tool_name: call.tool_name,
108→                    arguments: call.input,
109→                    status: ToolStatus::Running,
110→                    result: None,
111→                    timestamp: now,
112→                });
113→            }
114→            AgentEvent::ToolCallCompleted { result, .. } => {
115→                // Find and update the running tool block
116→                if let Some(UiBlock::ToolExecution {
117→                    status,
118→                    result: block_result,
119→                    ..
120→                }) = self.blocks.iter_mut().find(|b| {
121→                    if let UiBlock::ToolExecution { call_id, .. } = b {
122→                        call_id == &result.call_id
123→                    } else {
124→                        false
125→                    }
126→                }) {
127→                    *status = ToolStatus::Success;
128→                    *block_result = Some(result.output);
129→                }
130→            }
131→            AgentEvent::ToolCallFailed { call_id, error, .. } => {
132→                if let Some(UiBlock::ToolExecution { status, .. }) =
133→                    self.blocks.iter_mut().find(|b| {
134→                        if let UiBlock::ToolExecution { call_id: id, .. } = b {
135→                            id == &call_id
136→                        } else {
137→                            false
138→                        }
139→                    })
140→                {
141→                    *status = ToolStatus::Error(error);
142→                }
143→            }
144→            AgentEvent::RunFinished { final_answer, .. } => {
145→                if let Some(text) = self.streaming_text.take() {
146→                    if !self.last_assistant_message_matches(&text) {
147→                        self.blocks.push(UiBlock::AssistantMessage {
148→                            text,
149→                            timestamp: now,
150→                        });
151→                    }
152→                } else if let Some(ans) = final_answer {
153→                    if !self.last_assistant_message_matches(&ans) {
154→                        self.blocks.push(UiBlock::AssistantMessage {
155→                            text: ans,
156→                            timestamp: now,
157→                        });
158→                    }
159→                }
160→                self.is_busy = false;
161→            }
162→            AgentEvent::RunErrored { error, .. } => {
163→                self.blocks.push(UiBlock::SystemAlert {
164→                    text: format!("Run Error: {}", error),
165→                    timestamp: now,
166→                });
167→                self.is_busy = false;
168→            }
169→            AgentEvent::ApprovalRequested {
170→                approval_id,
171→                call_id,
172→                tool_name,
173→                arguments,
174→                risk,
175→                ..
176→            } => {
177→                self.is_busy = false;
178→                self.pending_approval = Some(ApprovalRequest {
179→                    approval_id,
180→                    call_id,
181→                    tool_name,
182→                    arguments,
183→                    risk_level: risk,
184→                });
185→            }
186→            AgentEvent::ApprovalResolved { decision, .. } => {
187→                self.pending_approval = None;
188→                self.blocks.push(UiBlock::SystemAlert {
189→                    text: format!("Tool execution was {}", decision),
190→                    timestamp: now,
191→                });
192→                self.is_busy = true; // Loop resumes
193→            }
194→            _ => {
195→                // Ignore other events for pure UI view state
196→            }
197→        }
198→    }
199→
200→    fn last_assistant_message_matches(&self, text: &str) -> bool {
201→        self.blocks
202→            .last()
203→            .and_then(|block| match block {
204→                UiBlock::AssistantMessage { text, .. } => Some(text.as_str()),
205→                _ => None,
206→            })
207→            .is_some_and(|last| last == text)
208→    }
209→}
