  5→/// Check whether a daemon is already healthy at the given URL.
  6→async fn is_daemon_healthy(base_url: &str) -> bool {
  7→    let url = format!("{base_url}/health");
  8→    let client = reqwest::Client::builder()
  9→        .timeout(Duration::from_secs(2))
 10→        .build();
 11→    let Ok(client) = client else { return false };
 12→    matches!(client.get(&url).send().await, Ok(resp) if resp.status().is_success())
 13→}
 14→
 15→/// Check if a PID file exists and the process is alive.
 16→/// Returns `Some(pid)` if alive, `None` if dead or no PID file.
 17→pub fn check_existing_pid(data_dir: &Path) -> Option<u32> {
 18→    let pid_path = data_dir.join("daemon.pid");
 19→    let raw = fs::read_to_string(&pid_path).ok()?;
 20→    let pid: u32 = raw.trim().parse().ok()?;
 21→
 22→    if is_process_alive(pid) {
 23→        Some(pid)
 24→    } else {
 25→        tracing::warn!(pid, "Stale daemon.pid found (process dead), removing");
 26→        let _ = fs::remove_file(&pid_path);
 27→        None
 28→    }
 29→}
 30→
 31→/// Check if a process with the given PID is alive using `kill -0`.
 32→#[cfg(unix)]
 33→pub fn is_process_alive(pid: u32) -> bool {
 34→    std::process::Command::new("kill")
 35→        .args(["-0", &pid.to_string()])
 36→        .stdout(std::process::Stdio::null())
 37→        .stderr(std::process::Stdio::null())
 38→        .status()
 39→        .is_ok_and(|s| s.success())
 40→}
 41→
 42→#[cfg(not(unix))]
 43→pub fn is_process_alive(_pid: u32) -> bool {
 44→    // On non-Unix, we can't cheaply check — assume alive if PID file exists.
 45→    true
 46→}
 47→
 48→/// Remove the daemon.pid file (called on graceful shutdown).
 49→pub fn remove_pid_file(data_dir: &Path) {
 50→    let pid_path = data_dir.join("daemon.pid");
 51→    if pid_path.exists() {
 52→        let _ = fs::remove_file(&pid_path);
 53→        tracing::info!("Removed daemon.pid");
 54→    }
 55→}
 56→
 57→/// Stop a running daemon by sending SIGTERM and waiting for exit.
 58→pub async fn stop_daemon(data_dir: &Path, port: u16) -> anyhow::Result<()> {
 59→    let base_url = format!("http://127.0.0.1:{port}");
 60→
 61→    // Check PID file first.
 62→    let Some(pid) = check_existing_pid(data_dir) else {
 63→        // No live process — check if the port is healthy anyway.
 64→        if is_daemon_healthy(&base_url).await {
 65→            anyhow::bail!(
 66→                "Daemon is healthy on {base_url} but no PID file found. Stop it manually."
 67→            );
 68→        }
 69→        anyhow::bail!("No running daemon found.");
 70→    };
 71→
 72→    // Send SIGTERM.
