        tracing::warn!(%error, "failed to persist last_session hint");
    }

    arcan_tui::run_tui(base_url, session).await
}
```

**Key behaviors:**
- **Auto-daemon**: If no `--url` is provided, it calls `daemon::ensure_daemon()` to spawn a background daemon
- **Session resolution**: Uses HTTP API to resolve the session (avoids direct redb journal lock conflicts)
- **TUI invocation**: Calls `arcan_tui::run_tui(base_url, session)`

---

### 3. **Daemon Auto-Start Mechanism** (`daemon.rs:109-186`)

When the daemon isn't running, `ensure_daemon()`:

1. **Checks health**: Probes `GET /health` on `http://127.0.0.1:{port}`
2. **Checks PID file**: Looks for `data_dir/daemon.pid` to detect existing processes
3. **Spawns detached child**: Executes `arcan serve --port {port} --data-dir {data_dir}` with stdout/stderr redirected to `daemon.log`
4. **Polls for health**: Waits up to ~12 seconds for the daemon to become healthy
5. **Returns base URL**: Once healthy, returns the daemon URL (`http://127.0.0.1:{port}`)

**Example file output:**
```
.arcan/
├── daemon.pid          # Process ID of running daemon
├── daemon.log          # Daemon stdout/stderr
├── journal.redb        # Event journal (locked during daemon run)
├── blobs/              # Content-addressed blob storage
├── memory/             # Memory tool state
└── logs/
    ├── tui.log         # TUI-specific logs
    ├── run.log         # CLI run logs
```

---

### 4. **TUI Initialization** (`lib.rs:23-53`)

The public entry point `run_tui()` in `arcan_tui`:

```rust
pub async fn run_tui(base_url: String, session_id: String) -> anyhow::Result<()> {
    // Setup terminal (raw mode, alternate screen, mouse capture)
    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen, EnableMouseCapture)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    // Create network config and app state
    let config = NetworkConfig {
        base_url,
        session_id,
    };
    let mut app = App::new(config);

    // Run the event loop
    let res = app.run(&mut terminal).await;

    // Restore terminal (disable raw mode, exit alternate screen)
    disable_raw_mode()?;
    execute!(terminal.backend_mut(), LeaveAlternateScreen, DisableMouseCapture)?;
    terminal.show_cursor()?;

    res
}
```

**Terminal setup:**
- Enters raw mode (character-by-character input)
- Enables alternate screen (doesn't clobber scrollback)
- Enables mouse capture
- Creates a `CrosstermBackend` for rendering

---

### 5. **App Architecture** (`app.rs`)

The `App` struct manages the event loop:

```rust
pub struct App {
    pub state: AppState,        // Pure UI state (no IO dependency)
    pub should_quit: bool,
    pub client: Arc<NetworkClient>,
    pub event_rx: mpsc::Receiver<AgentEvent>,
}
```

**Initialization:**
```rust
pub fn new(config: NetworkConfig) -> Self {
    let client = Arc::new(NetworkClient::new(config));
    let (tx, rx) = mpsc::channel(100);

    // Spawn network listener
    let listener_client = client.clone();
    tokio::spawn(async move {
        if let Err(e) = listener_client.listen_events(tx).await {
            tracing::error!("Event listener ended: {}", e);
        }
    });

    Self {
        state: AppState::new(),
        should_quit: false,
        client,
        event_rx: rx,
    }
}
```

**Key pattern:** Network listener runs in background, pushes `AgentEvent`s to a channel. The main event loop drains this channel non-blocking.

---

### 6. **Event Loop** (`app.rs:118-234`)

The main render → receive events → handle input cycle:

```rust
pub async fn run<B: Backend>(&mut self, terminal: &mut Terminal<B>) -> anyhow::Result<()> {
    loop {
        // Draw UI
        terminal.draw(|f| ui::draw(f, &self.state))?;

        // Process external AgentEvents (non-blocking drain)
        while let Ok(event) = self.event_rx.try_recv() {
            self.state.apply_event(event);
        }

        // Handle UI events (50ms timeout)
        if event::poll(Duration::from_millis(50))? {
            if let Event::Key(key) = event::read()? {
                match key.code {
                    KeyCode::Esc | Ctrl-C => self.should_quit = true,
                    KeyCode::Char(c) => self.state.input_buffer.push(c),
                    KeyCode::Backspace => self.state.input_buffer.pop(),
                    KeyCode::Enter => {
                        // Send message or handle commands (/model, /approve, /clear)
                        self.state.input_buffer.clear();
                    }
                    _ => {}
                }
            }
        }

        if self.should_quit { break; }
    }
    Ok(())
}
```

