### 8. **State Management** (`models.rs`)

Pure logical state with zero Ratatui dependency:

```rust
pub struct AppState {
    pub blocks: Vec<UiBlock>,        // Conversation history
    pub streaming_text: Option<String>, // Pending text deltas
    pub input_buffer: String,        // User input being typed
    pub pending_approval: Option<ApprovalRequest>, // Approval gate
    pub is_busy: bool,               // Waiting for daemon
}
```

**Event application:**
```rust
pub fn apply_event(&mut self, event: AgentEvent) {
    match event {
        AgentEvent::TextDelta { delta, .. } => {
            // Accumulate streaming text
            if let Some(mut text) = self.streaming_text.take() {
                text.push_str(&delta);
                self.streaming_text = Some(text);
            } else {
                self.streaming_text = Some(delta);
            }
        }
        AgentEvent::ToolCallRequested { call, .. } => {
            // Flush previous streaming text, create ToolExecution block
            if let Some(text) = self.streaming_text.take() {
                self.blocks.push(UiBlock::AssistantMessage { text, ... });
            }
            self.blocks.push(UiBlock::ToolExecution {
                call_id: call.call_id,
                tool_name: call.tool_name,
                status: ToolStatus::Running,
                ...
            });
        }
        AgentEvent::ApprovalRequested { approval_id, ... } => {
            self.pending_approval = Some(ApprovalRequest { ... });
        }
        // ... etc
    }
}
```

