### 9. **UI Rendering** (`ui.rs`)

Ratatui-based renderer:

```rust
pub fn draw(f: &mut Frame, state: &AppState) {
    // Split into chat log (min 3 rows) and input box (3 rows)
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Min(3), Constraint::Length(3)])
        .split(f.area());

    // Render chat history blocks (HumanMessage, AssistantMessage, ToolExecution, SystemAlert)
    let mut message_lines = Vec::new();
    for block in &state.blocks {
        match block {
            UiBlock::HumanMessage { text, .. } => {
                message_lines.push(Line::from(vec![
                    Span::styled("You: ", Color::Blue),
                    Span::raw(text),
                ]));
            }
            UiBlock::AssistantMessage { text, .. } => {
                message_lines.push(Line::from(vec![
                    Span::styled("Assistant: ", Color::Green),
                    Span::raw(text),
                ]));
            }
            UiBlock::ToolExecution { tool_name, status, .. } => {
                let status_str = match status {
                    ToolStatus::Running => "(Running...)",
                    ToolStatus::Success => "[OK]",
                    ToolStatus::Error(_) => "[ERR]",
                };
                message_lines.push(Line::from(vec![
                    Span::styled("Tool ", Color::Yellow),
                    Span::raw(format!("{} {}", tool_name, status_str)),
                ]));
            }
            // ...
        }
    }

    // Render streaming text with cursor
    if let Some(streaming) = &state.streaming_text {
        message_lines.push(Line::from(vec![
            Span::styled("Assistant: ", Color::Green),
            Span::raw(streaming),
            Span::styled(" █", Color::Gray),
        ]));
    }

    // Render input box with status indicator
    let prompt = if state.pending_approval.is_some() {
        format!("Approval Req: (yes/no) > {}", state.input_buffer)
    } else {
        format!("❯ {}", state.input_buffer)
    };

    f.render_widget(messages_block, chunks[0]);
    f.render_widget(input_block, chunks[1]);
}
```

