 24→
 25→fn parse_protocol_record(data: &str) -> Option<AgentEvent> {
 26→    let record: ProtocolEventRecord = serde_json::from_str(data).ok()?;
 27→    agent_event_from_protocol_record(&record)
 28→}
 29→
 30→fn parse_canonical_event(event_name: &str, data: &str, session_id: &str) -> Option<AgentEvent> {
 31→    let payload: Value = serde_json::from_str(data).ok()?;
 32→    let run_id = "stream".to_string();
 33→    let session_id = session_id.to_string();
 34→
 35→    match event_name {
 36→        "assistant.text.delta" => {
 37→            let delta = payload.get("delta")?.as_str()?.to_string();
 38→            Some(AgentEvent::TextDelta {
 39→                run_id,
 40→                session_id,
 41→                iteration: 0,
 42→                delta,
 43→            })
 44→        }
 45→        "assistant.message.committed" => {
 46→            let content = payload.get("content")?.as_str()?.to_string();
 47→            Some(AgentEvent::RunFinished {
 48→                run_id,
 49→                session_id,
 50→                reason: RunStopReason::Completed,
 51→                total_iterations: 0,
 52→                final_answer: Some(content),
 53→            })
 54→        }
 55→        "tool.started" => {
 56→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
 57→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
 58→            let arguments = payload
 59→                .get("arguments")
 60→                .cloned()
 61→                .unwrap_or_else(|| json!({}));
 62→            Some(AgentEvent::ToolCallRequested {
 63→                run_id,
 64→                session_id,
 65→                iteration: 0,
 66→                call: ToolCall {
 67→                    call_id,
 68→                    tool_name,
 69→                    input: arguments,
 70→                },
 71→            })
 72→        }
 73→        "tool.completed" => {
 74→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
 75→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
 76→            let status = payload
 77→                .get("status")
 78→                .and_then(Value::as_str)
 79→                .unwrap_or("ok")
 80→                .to_string();
 81→            if status == "ok" {
 82→                Some(AgentEvent::ToolCallCompleted {
 83→                    run_id,
 84→                    session_id,
 85→                    iteration: 0,
 86→                    result: ToolResultSummary {
 87→                        call_id,
 88→                        tool_name,
 89→                        output: payload.get("result").cloned().unwrap_or(Value::Null),
 90→                    },
 91→                })
 92→            } else {
 93→                let error = payload
 94→                    .get("error")
 95→                    .and_then(Value::as_str)
 96→                    .unwrap_or("tool call failed")
 97→                    .to_string();
 98→                Some(AgentEvent::ToolCallFailed {
 99→                    run_id,
100→                    session_id,
101→                    iteration: 0,
102→                    call_id,
103→                    tool_name,
104→                    error,
105→                })
106→            }
107→        }
108→        "intent.evaluated" => {
109→            if !payload
110→                .get("requires_approval")
111→                .and_then(Value::as_bool)
112→                .unwrap_or(false)
113→            {
114→                return None;
115→            }
116→            let approval_id = payload.get("approval_id")?.as_str()?.to_string();
117→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
118→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
119→            let arguments = payload
120→                .get("arguments")
121→                .cloned()
122→                .unwrap_or_else(|| json!({}));
123→            let risk = payload
124→                .get("risk")
125→                .and_then(Value::as_str)
126→                .unwrap_or("unknown")
127→                .to_string();
128→            Some(AgentEvent::ApprovalRequested {
129→                run_id,
130→                session_id,
131→                approval_id,
132→                call_id,
133→                tool_name,
134→                arguments,
135→                risk,
136→            })
137→        }
138→        "intent.approved" | "intent.rejected" => {
139→            let approval_id = payload.get("approval_id")?.as_str()?.to_string();
140→            let decision = payload
141→                .get("decision")
142→                .and_then(Value::as_str)
143→                .unwrap_or_else(|| {
144→                    if event_name == "intent.approved" {
145→                        "approved"
146→                    } else {
147→                        "denied"
148→                    }
149→                })
150→                .to_string();
151→            let reason = payload
152→                .get("reason")
153→                .and_then(Value::as_str)
154→                .map(str::to_string);
155→            Some(AgentEvent::ApprovalResolved {
156→                run_id,
157→                session_id,
158→                approval_id,
159→                decision,
160→                reason,
161→            })
162→        }
163→        _ => None,
164→    }
165→}
166→
167→fn risk_level_to_string(level: ProtocolRiskLevel) -> &'static str {
168→    match level {
169→        ProtocolRiskLevel::Low => "low",
170→        ProtocolRiskLevel::Medium => "medium",
171→        ProtocolRiskLevel::High => "high",
172→        ProtocolRiskLevel::Critical => "critical",
173→    }
174→}
175→
176→fn approval_decision_to_string(decision: ProtocolApprovalDecision) -> &'static str {
177→    match decision {
178→        ProtocolApprovalDecision::Approved => "approved",
179→        ProtocolApprovalDecision::Denied => "denied",
180→        ProtocolApprovalDecision::Timeout => "timeout",
181→    }
182→}
183→
184→fn run_stop_reason_from_string(reason: &str) -> RunStopReason {
185→    match reason {
186→        "completed" => RunStopReason::Completed,
187→        "needs_user" => RunStopReason::NeedsUser,
188→        "blocked_by_policy" => RunStopReason::BlockedByPolicy,
189→        "budget_exceeded" => RunStopReason::BudgetExceeded,
190→        "cancelled" => RunStopReason::Cancelled,
191→        _ => RunStopReason::Error,
192→    }
193→}
194→
195→fn agent_event_from_protocol_record(record: &ProtocolEventRecord) -> Option<AgentEvent> {
196→    let run_id = "stream".to_string();
197→    let session_id = record.session_id.to_string();
198→
199→    match &record.kind {
200→        ProtocolEventKind::RunStarted {
201→            provider,
202→            max_iterations,
203→        } => Some(AgentEvent::RunStarted {
204→            run_id,
205→            session_id,
206→            provider: provider.clone(),
207→            max_iterations: *max_iterations,
208→        }),
209→        ProtocolEventKind::StepStarted { index } => Some(AgentEvent::IterationStarted {
210→            run_id,
211→            session_id,
212→            iteration: *index,
213→        }),
214→        ProtocolEventKind::StepFinished {
215→            index,
216→            stop_reason,
217→            directive_count,
218→        } => Some(AgentEvent::ModelOutput {
219→            run_id,
220→            session_id,
221→            iteration: *index,
222→            stop_reason: match stop_reason.as_str() {
223→                "end_turn" => arcan_core::protocol::ModelStopReason::EndTurn,
224→                "tool_use" => arcan_core::protocol::ModelStopReason::ToolUse,
225→                "needs_user" => arcan_core::protocol::ModelStopReason::NeedsUser,
226→                "max_tokens" => arcan_core::protocol::ModelStopReason::MaxTokens,
227→                "safety" => arcan_core::protocol::ModelStopReason::Safety,
228→                _ => arcan_core::protocol::ModelStopReason::Unknown,
229→            },
230→            directive_count: *directive_count,
231→            usage: None,
232→        }),
233→        ProtocolEventKind::AssistantTextDelta { delta, index }
234→        | ProtocolEventKind::TextDelta { delta, index } => Some(AgentEvent::TextDelta {
235→            run_id,
236→            session_id,
237→            iteration: index.unwrap_or(0),
238→            delta: delta.clone(),
239→        }),
240→        ProtocolEventKind::AssistantMessageCommitted { content, .. }
241→        | ProtocolEventKind::Message { content, .. } => Some(AgentEvent::RunFinished {
242→            run_id,
243→            session_id,
244→            reason: RunStopReason::Completed,
245→            total_iterations: 0,
246→            final_answer: Some(content.clone()),
247→        }),
248→        ProtocolEventKind::ToolCallRequested {
249→            call_id,
250→            tool_name,
251→            arguments,
252→            ..
253→        } => Some(AgentEvent::ToolCallRequested {
254→            run_id,
255→            session_id,
256→            iteration: 0,
257→            call: ToolCall {
258→                call_id: call_id.clone(),
259→                tool_name: tool_name.clone(),
260→                input: arguments.clone(),
261→            },
262→        }),
263→        ProtocolEventKind::ToolCallCompleted {
264→            call_id,
265→            tool_name,
266→            result,
267→            status,
268→            ..
269→        } => {
270→            if *status == ProtocolSpanStatus::Ok {
271→                Some(AgentEvent::ToolCallCompleted {
272→                    run_id,
273→                    session_id,
274→                    iteration: 0,
275→                    result: ToolResultSummary {
276→                        call_id: call_id.clone().unwrap_or_default(),
277→                        tool_name: tool_name.clone(),
278→                        output: result.clone(),
279→                    },
280→                })
281→            } else {
282→                Some(AgentEvent::ToolCallFailed {
283→                    run_id,
284→                    session_id,
285→                    iteration: 0,
286→                    call_id: call_id.clone().unwrap_or_default(),
287→                    tool_name: tool_name.clone(),
288→                    error: result
289→                        .get("error")
290→                        .and_then(Value::as_str)
291→                        .unwrap_or("tool call failed")
292→                        .to_string(),
293→                })
294→            }
295→        }
296→        ProtocolEventKind::ToolCallFailed {
297→            call_id,
298→            tool_name,
299→            error,
300→        } => Some(AgentEvent::ToolCallFailed {
301→            run_id,
302→            session_id,
303→            iteration: 0,
304→            call_id: call_id.clone(),
305→            tool_name: tool_name.clone(),
306→            error: error.clone(),
307→        }),
308→        ProtocolEventKind::StatePatched {
309→            index,
310→            patch,
311→            revision,
312→        } => Some(AgentEvent::StatePatched {
313→            run_id,
314→            session_id,
315→            iteration: index.unwrap_or(0),
316→            patch: arcan_core::protocol::StatePatch {
317→                format: arcan_core::protocol::StatePatchFormat::MergePatch,
318→                patch: patch.clone(),
319→                source: arcan_core::protocol::StatePatchSource::System,
320→            },
321→            revision: *revision,
322→        }),
323→        ProtocolEventKind::ContextCompacted {
324→            dropped_count,
325→            tokens_before,
326→            tokens_after,
327→        } => Some(AgentEvent::ContextCompacted {
328→            run_id,
329→            session_id,
330→            iteration: 0,
331→            dropped_count: *dropped_count,
332→            tokens_before: *tokens_before,
333→            tokens_after: *tokens_after,
334→        }),
335→        ProtocolEventKind::ApprovalRequested {
336→            approval_id,
337→            call_id,
338→            tool_name,
339→            arguments,
340→            risk,
341→        } => Some(AgentEvent::ApprovalRequested {
342→            run_id,
343→            session_id,
344→            approval_id: approval_id.to_string(),
345→            call_id: call_id.clone(),
346→            tool_name: tool_name.clone(),
347→            arguments: arguments.clone(),
348→            risk: risk_level_to_string(*risk).to_string(),
349→        }),
350→        ProtocolEventKind::ApprovalResolved {
351→            approval_id,
352→            decision,
353→            reason,
354→        } => Some(AgentEvent::ApprovalResolved {
355→            run_id,
356→            session_id,
357→            approval_id: approval_id.to_string(),
358→            decision: approval_decision_to_string(*decision).to_string(),
359→            reason: reason.clone(),
360→        }),
361→        ProtocolEventKind::RunFinished {
362→            reason,
363→            total_iterations,
364→            final_answer,
365→            ..
366→        } => Some(AgentEvent::RunFinished {
367→            run_id,
368→            session_id,
369→            reason: run_stop_reason_from_string(reason),
370→            total_iterations: *total_iterations,
371→            final_answer: final_answer.clone(),
372→        }),
373→        ProtocolEventKind::RunErrored { error } => Some(AgentEvent::RunErrored {
374→            run_id,
375→            session_id,
376→            error: error.clone(),
377→        }),
378→        _ => None,
379→    }
380→}
381→
382→fn parse_vercel_v6_part(data: &str) -> Option<AgentEvent> {
383→    let value: Value = serde_json::from_str(data).ok()?;
384→    if value.get("type").and_then(Value::as_str) != Some("data-aios-event") {
385→        return None;
386→    }
387→    let record_value = value.get("data")?.clone();
388→    let record: ProtocolEventRecord = serde_json::from_value(record_value).ok()?;
389→    agent_event_from_protocol_record(&record)
390→}
