 9→
10→pub fn draw(f: &mut Frame, state: &AppState) {
11→    let chunks = Layout::default()
12→        .direction(Direction::Vertical)
13→        .margin(1)
14→        .constraints([
15→            Constraint::Min(3),    // Chat log
16→            Constraint::Length(3), // Input box
17→        ])
18→        .split(f.area());
19→
20→    // Messages Area
21→    let mut message_lines = Vec::new();
22→    for block in &state.blocks {
23→        match block {
24→            UiBlock::HumanMessage { text, timestamp: _ } => {
25→                message_lines.push(Line::from(vec![
26→                    Span::styled("You: ", Style::default().fg(Color::Blue)),
27→                    Span::raw(text.clone()),
28→                ]));
29→            }
30→            UiBlock::AssistantMessage { text, timestamp: _ } => {
31→                message_lines.push(Line::from(vec![
32→                    Span::styled("Assistant: ", Style::default().fg(Color::Green)),
33→                    Span::raw(text.clone()),
34→                ]));
35→            }
36→            UiBlock::ToolExecution {
37→                tool_name, status, ..
38→            } => {
39→                let status_str = match status {
40→                    crate::models::ToolStatus::Running => "(Running...)",
41→                    crate::models::ToolStatus::Success => "[OK]",
42→                    crate::models::ToolStatus::Error(_) => "[ERR]",
43→                };
44→                message_lines.push(Line::from(vec![
45→                    Span::styled("Tool ", Style::default().fg(Color::Yellow)),
46→                    Span::styled(
47→                        format!("{} {}", tool_name, status_str),
48→                        Style::default().fg(Color::Yellow),
49→                    ),
50→                ]));
51→            }
52→            UiBlock::SystemAlert { text, .. } => {
53→                message_lines.push(Line::from(vec![
54→                    Span::styled("System: ", Style::default().fg(Color::Red)),
55→                    Span::styled(text.clone(), Style::default().fg(Color::Red)),
56→                ]));
57→            }
58→        }
59→    }
60→
61→    if let Some(streaming) = &state.streaming_text {
62→        message_lines.push(Line::from(vec![
63→            Span::styled("Assistant: ", Style::default().fg(Color::Green)),
64→            Span::raw(streaming.clone()),
65→            Span::styled(" █", Style::default().fg(Color::Gray)),
66→        ]));
67→    }
68→
69→    let messages_block = Paragraph::new(message_lines)
70→        .block(
71→            Block::default()
72→                .borders(Borders::ALL)
73→                .title(" Session Log "),
74→        )
75→        .wrap(Wrap { trim: false });
76→    f.render_widget(messages_block, chunks[0]);
77→
78→    // Input Area
79→    let prompt = if let Some(approval) = &state.pending_approval {
80→        format!(
81→            "Approval Req for {}: (yes/no) > {}",
82→            approval.tool_name, state.input_buffer
83→        )
84→    } else {
85→        format!("❯ {}", state.input_buffer)
86→    };
87→
88→    let input_block = Paragraph::new(prompt)
89→        .block(Block::default().borders(Borders::ALL).title(" Input "))
90→        .style(if state.pending_approval.is_some() {
91→            Style::default().fg(Color::Red)
92→        } else {
93→            Style::default().fg(Color::White)
94→        });
95→    f.render_widget(input_block, chunks[1]);
96→}
