 14→/// Configuration for the daemon connection
 15→pub struct NetworkConfig {
 16→    pub base_url: String,
 17→    pub session_id: String,
 18→}
 19→
 20→pub struct NetworkClient {
 21→    client: Client,
 22→    config: NetworkConfig,
 23→}
 24→
 25→fn parse_protocol_record(data: &str) -> Option<AgentEvent> {
 26→    let record: ProtocolEventRecord = serde_json::from_str(data).ok()?;
 27→    agent_event_from_protocol_record(&record)
 28→}
