 30→fn parse_canonical_event(event_name: &str, data: &str, session_id: &str) -> Option<AgentEvent> {
 31→    let payload: Value = serde_json::from_str(data).ok()?;
 32→    let run_id = "stream".to_string();
 33→    let session_id = session_id.to_string();
 34→
 35→    match event_name {
 36→        "assistant.text.delta" => {
 37→            let delta = payload.get("delta")?.as_str()?.to_string();
 38→            Some(AgentEvent::TextDelta {
 39→                run_id,
 40→                session_id,
 41→                iteration: 0,
 42→                delta,
 43→            })
 44→        }
 45→        "assistant.message.committed" => {
 46→            let content = payload.get("content")?.as_str()?.to_string();
 47→            Some(AgentEvent::RunFinished {
 48→                run_id,
 49→                session_id,
 50→                reason: RunStopReason::Completed,
 51→                total_iterations: 0,
 52→                final_answer: Some(content),
 53→            })
 54→        }
 55→        "tool.started" => {
 56→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
 57→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
 58→            let arguments = payload
 59→                .get("arguments")
 60→                .cloned()
 61→                .unwrap_or_else(|| json!({}));
 62→            Some(AgentEvent::ToolCallRequested {
 63→                run_id,
 64→                session_id,
 65→                iteration: 0,
 66→                call: ToolCall {
 67→                    call_id,
 68→                    tool_name,
 69→                    input: arguments,
 70→                },
 71→            })
 72→        }
 73→        "tool.completed" => {
 74→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
 75→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
 76→            let status = payload
 77→                .get("status")
 78→                .and_then(Value::as_str)
 79→                .unwrap_or("ok")
 80→                .to_string();
 81→            if status == "ok" {
 82→                Some(AgentEvent::ToolCallCompleted {
 83→                    run_id,
 84→                    session_id,
 85→                    iteration: 0,
 86→                    result: ToolResultSummary {
 87→                        call_id,
 88→                        tool_name,
 89→                        output: payload.get("result").cloned().unwrap_or(Value::Null),
 90→                    },
 91→                })
 92→            } else {
 93→                let error = payload
 94→                    .get("error")
 95→                    .and_then(Value::as_str)
 96→                    .unwrap_or("tool call failed")
 97→                    .to_string();
 98→                Some(AgentEvent::ToolCallFailed {
 99→                    run_id,
100→                    session_id,
101→                    iteration: 0,
102→                    call_id,
103→                    tool_name,
104→                    error,
105→                })
106→            }
107→        }
108→        "intent.evaluated" => {
109→            if !payload
110→                .get("requires_approval")
111→                .and_then(Value::as_bool)
112→                .unwrap_or(false)
113→            {
114→                return None;
115→            }
116→            let approval_id = payload.get("approval_id")?.as_str()?.to_string();
117→            let call_id = payload.get("intent_id")?.as_str()?.to_string();
118→            let tool_name = payload.get("tool_name")?.as_str()?.to_string();
119→            let arguments = payload
120→                .get("arguments")
121→                .cloned()
122→                .unwrap_or_else(|| json!({}));
123→            let risk = payload
124→                .get("risk")
125→                .and_then(Value::as_str)
126→                .unwrap_or("unknown")
127→                .to_string();
128→            Some(AgentEvent::ApprovalRequested {
129→                run_id,
130→                session_id,
131→                approval_id,
132→                call_id,
133→                tool_name,
134→                arguments,
135→                risk,
136→            })
137→        }
138→        "intent.approved" | "intent.rejected" => {
139→            let approval_id = payload.get("approval_id")?.as_str()?.to_string();
140→            let decision = payload
141→                .get("decision")
142→                .and_then(Value::as_str)
143→                .unwrap_or_else(|| {
144→                    if event_name == "intent.approved" {
145→                        "approved"
146→                    } else {
147→                        "denied"
148→                    }
149→                })
150→                .to_string();
151→            let reason = payload
152→                .get("reason")
153→                .and_then(Value::as_str)
154→                .map(str::to_string);
155→            Some(AgentEvent::ApprovalResolved {
156→                run_id,
157→                session_id,
158→                approval_id,
159→                decision,
160→                reason,
161→            })
162→        }
163→        _ => None,
164→    }
165→}
